    """Suppress false reversals based on local volatility."""
    n = len(signal)
    if n < 3:
        return signal.copy()

    output = signal.copy()

    local_window = 15
    for i in range(1, n - 1):
        start = max(0, i - local_window)
        end = min(n, i + local_window)
        local_std = np.std(signal[start:end])

        prev_diff = signal[i] - signal[i-1]
        next_diff = signal[i+1] - signal[i]

        if prev_diff * next_diff < 0:
            magnitude = min(abs(prev_diff), abs(next_diff))
            if magnitude < threshold_factor * local_std:
                output[i] = 0.5 * (signal[i-1] + signal[i+1])

    return output

