def slope_change_suppression(signal, min_run_length=5):
    """
    Suppress short monotone runs by extending longer adjacent runs.
    A slope change is when diff changes sign. Short segments between
    slope changes get interpolated away.
    """
    n = len(signal)
    if n < 4:
        return signal.copy()

    diffs = np.diff(signal)
    signs = np.sign(diffs)

    # Find runs of same-sign differences
    runs = []
    start = 0
    for i in range(1, len(signs)):
        if signs[i] != signs[start] and signs[i] != 0 and signs[start] != 0:
            runs.append((start, i, signs[start]))
            start = i
    runs.append((start, len(signs), signs[start]))

    output = signal.copy()

    # Interpolate over short runs
    for idx, (rs, re, s) in enumerate(runs):
        run_len = re - rs
        if run_len < min_run_length:
            # Linear interpolation from start to end of this short segment
            seg_start = rs
            seg_end = re
            output[seg_start:seg_end+1] = np.linspace(
                signal[seg_start], signal[seg_end], seg_end - seg_start + 1
            )

    return output

